def solution(physical_count, system_records):
    from collections import Counter

    physical_freq = Counter(physical_count)
    system_freq = Counter(system_records)

    all_ids = set(physical_freq.keys()) | set(system_freq.keys())

    discrepancies = []
    for product_id in all_ids:
        if physical_freq.get(product_id, 0) != system_freq.get(product_id, 0):
            discrepancies.append(product_id)

    return discrepancies

