function solution(physical_count, system_records) {
  const physicalFreq = {};
  const systemFreq = {};

  for (const id of physical_count) {
    physicalFreq[id] = (physicalFreq[id] || 0) + 1;
  }

  for (const id of system_records) {
    systemFreq[id] = (systemFreq[id] || 0) + 1;
  }

  const allIds = new Set([...Object.keys(physicalFreq), ...Object.keys(systemFreq)]);
  const discrepancies = [];

  for (const id of allIds) {
    const physicalCount = physicalFreq[id] || 0;
    const systemCount = systemFreq[id] || 0;
    if (physicalCount !== systemCount) {
      discrepancies.push(parseInt(id));
    }
  }

  return discrepancies;
}

