reference_solution.javascript:
function solution(transitions) {
  if (transitions.length === 0) {
    return [];
  }

  // Build a graph: nextSongMap[song] = following_song
  const nextSongMap = {};
  const allSongs = new Set();
  const songsWithPredecessor = new Set();

  for (const [prevSong, nextSong] of transitions) {
    nextSongMap[prevSong] = nextSong;
    allSongs.add(prevSong);
    allSongs.add(nextSong);
    songsWithPredecessor.add(nextSong);
  }

  // Find the first song (one with no predecessor)
  let firstSong = null;
  for (const song of allSongs) {
    if (!songsWithPredecessor.has(song)) {
      firstSong = song;
      break;
    }
  }

  // Reconstruct the playlist by following the chain
  const playlist = [];
  let current = firstSong;
  while (current !== null && current !== undefined) {
    playlist.push(current);
    current = nextSongMap[current];
  }

  return playlist;
}

