reference_solution.python:
def solution(logs):
    from collections import defaultdict, deque

    if not logs:
        return []

    # Build graph: for each package, track checkpoint order
    pkg_order = defaultdict(list)
    for pkg_id, checkpoint in logs:
        pkg_order[pkg_id].append(checkpoint)

    # Build directed graph and in-degree count
    graph = defaultdict(set)
    in_degree = defaultdict(int)
    all_checkpoints = set()

    for pkg_id, checkpoints in pkg_order.items():
        for i in range(len(checkpoints) - 1):
            u, v = checkpoints[i], checkpoints[i + 1]
            if v not in graph[u]:
                graph[u].add(v)
                in_degree[v] += 1
            all_checkpoints.add(u)
            all_checkpoints.add(v)
        if checkpoints:
            all_checkpoints.add(checkpoints[-1])

    # Initialize in-degree for all checkpoints
    for cp in all_checkpoints:
        if cp not in in_degree:
            in_degree[cp] = 0

    # Kahn's algorithm (topological sort)
    queue = deque([cp for cp in all_checkpoints if in_degree[cp] == 0])
    result = []

    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbor in sorted(graph[node]):  # Sort for determinism
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # If not all checkpoints are included, there's a cycle (conflict)
    if len(result) != len(all_checkpoints):
        return []

    return result

