function solution(logs) {
  if (!logs || logs.length === 0) return [];

  const pkgOrder = new Map();

  // Group checkpoints by package
  for (const [pkg_id, checkpoint] of logs) {
    if (!pkgOrder.has(pkg_id)) {
      pkgOrder.set(pkg_id, []);
    }
    pkgOrder.get(pkg_id).push(checkpoint);
  }

  // Build graph and compute in-degrees
  const graph = new Map();
  const inDegree = new Map();
  const allCheckpoints = new Set();

  for (const [pkg_id, checkpoints] of pkgOrder.entries()) {
    for (let i = 0; i < checkpoints.length - 1; i++) {
      const u = checkpoints[i];
      const v = checkpoints[i + 1];

      if (!graph.has(u)) graph.set(u, new Set());
      if (!graph.get(u).has(v)) {
        graph.get(u).add(v);
        inDegree.set(v, (inDegree.get(v) || 0) + 1);
      }

      allCheckpoints.add(u);
      allCheckpoints.add(v);
    }
    if (checkpoints.length > 0) {
      allCheckpoints.add(checkpoints[checkpoints.length - 1]);
    }
  }

  // Initialize in-degrees for all checkpoints
  for (const cp of allCheckpoints) {
    if (!inDegree.has(cp)) {
      inDegree.set(cp, 0);
    }
  }

  // Topological sort using Kahn's algorithm
  const queue = [];
  for (const cp of allCheckpoints) {
    if (inDegree.get(cp) === 0) {
      queue.push(cp);
    }
  }

  const result = [];
  while (queue.length > 0) {
    const node = queue.shift();
    result.push(node);

    if (graph.has(node)) {
      const neighbors = Array.from(graph.get(node)).sort();
      for (const neighbor of neighbors) {
        inDegree.set(neighbor, inDegree.get(neighbor) - 1);
        if (inDegree.get(neighbor) === 0) {
          queue.push(neighbor);
        }
      }
    }
  }

  // Check if all checkpoints are included (cycle detection)
  if (result.length !== allCheckpoints.size) {
    return [];
  }

  return result;
}

