import math

def solution(packages, hours_deadline):
    def total_time_at_speed(speed):
        return sum(math.ceil(weight / speed) for weight in packages)

    left, right = 1, max(packages)

    while left < right:
        mid = (left + right) // 2
        if total_time_at_speed(mid) <= hours_deadline:
            right = mid
        else:
            left = mid + 1

    return left

