import java.util.*;

class Solution {
    public List<String> solution(String[] words) {
        Map<String, Integer> frequency = new HashMap<>();
        List<String> duplicates = new ArrayList<>();
        Set<String> added = new HashSet<>();

        // Count word frequencies (case-insensitive)
        for (String word : words) {
            String lower = word.toLowerCase();
            frequency.put(lower, frequency.getOrDefault(lower, 0) + 1);
        }

        // Find duplicates in order of first duplicate occurrence
        for (String word : words) {
            String lower = word.toLowerCase();
            if (frequency.get(lower) > 1 && !added.contains(lower)) {
                duplicates.add(lower);
                added.add(lower);
            }
        }

        return duplicates;
    }
}

