class Solution {
    public int[] solution(int[] queue1, int[] queue2) {
        int[] result = new int[queue1.length + queue2.length];
        int i = 0, j = 0, k = 0;

        // Two-pointer merge: advance pointers based on which element is smaller
        while (i < queue1.length && j < queue2.length) {
            if (queue1[i] <= queue2[j]) {
                result[k++] = queue1[i++];
            } else {
                result[k++] = queue2[j++];
            }
        }

        // Append remaining elements from queue1
        while (i < queue1.length) {
            result[k++] = queue1[i++];
        }

        // Append remaining elements from queue2
        while (j < queue2.length) {
            result[k++] = queue2[j++];
        }

        return result;
    }
}

