def solution(*args):
    if len(args) == 3:
        orders, refunds, n = args
        refund_set = set(refunds)
        counts = {}
        for pair in orders:
            customer_id, order_id = pair[0], pair[1]
            if customer_id not in counts:
                counts[customer_id] = 0
            if order_id in refund_set:
                counts[customer_id] += 1
        all_customers = list(counts.keys())
        all_customers.sort(key=lambda c: (-counts[c], c))
        return all_customers[:n]
    elif len(args) == 2:
        orders, refunds = args
        refund_set = set(refunds)
        return [o for o in orders if o not in refund_set]
    else:
        order_ids = args[0]
        seen = set()
        duplicates = []
        dup_set = set()
        for oid in order_ids:
            if oid in seen and oid not in dup_set:
                duplicates.append(oid)
                dup_set.add(oid)
            seen.add(oid)
        return duplicates

