function solution(...args) {
  if (args.length === 3) {
    const [orders, refunds, n] = args;
    const refundSet = new Set(refunds);
    const counts = {};
    for (const pair of orders) {
      const customerId = pair[0];
      const orderId = pair[1];
      if (!(customerId in counts)) counts[customerId] = 0;
      if (refundSet.has(orderId)) counts[customerId]++;
    }
    const allCustomers = Object.keys(counts);
    allCustomers.sort((a, b) => counts[b] - counts[a] || a.localeCompare(b));
    return allCustomers.slice(0, n);
  } else if (args.length === 2) {
    const [orders, refunds] = args;
    const refundSet = new Set(refunds);
    return orders.filter(o => !refundSet.has(o));
  } else {
    const orderIds = args[0];
    const seen = new Set();
    const dupSet = new Set();
    const duplicates = [];
    for (const oid of orderIds) {
      if (seen.has(oid) && !dupSet.has(oid)) {
        duplicates.push(oid);
        dupSet.add(oid);
      }
      seen.add(oid);
    }
    return duplicates;
  }
}

