INSERT INTO messages (message_id, account_id, from_number, to_number, sent_at, status, cost_usd, direction)
SELECT row_number() OVER (ORDER BY 1) + 6, 1, '+14155552671', '+1415555' || substr('0000' || (row_number() OVER (ORDER BY 1) + 2700), -4), '2024-12-' || substr('0' || (((row_number() OVER (ORDER BY 1) - 1) % 25) + 1), -2) || ' ' || substr('0' || (((row_number() OVER (ORDER BY 1) - 1) / 25) % 24), -2) || ':00:00', 'delivered', 0.0075, 'outbound'
FROM (WITH RECURSIVE cnt(x) AS (SELECT 1 UNION ALL SELECT x+1 FROM cnt WHERE x < 10010) SELECT x FROM cnt);

