  let currMax = nums[0];
  let currMin = nums[0];
  let globalMax = nums[0];
  for (let i = 1; i < nums.length; i++) {
    const num = nums[i];
    const newMax = Math.max(num, currMax * num, currMin * num);
    const newMin = Math.min(num, currMax * num, currMin * num);
    currMax = newMax;
    currMin = newMin;
    globalMax = Math.max(globalMax, currMax);
  }
  return globalMax;
}

