  // Encode
  let encoded = strs.map(s => `${s.length}#${s}`).join('');
  // Decode
  const result = [];
  let i = 0;
  while (i < encoded.length) {
    let j = encoded.indexOf('#', i);
    const length = parseInt(encoded.slice(i, j));
    result.push(encoded.slice(j + 1, j + 1 + length));
    i = j + 1 + length;
  }
  return result;
}

