def solution(operations, args_list):
    class FileSystemNode:
        def __init__(self):
            self.children = {}
            self.content = ''

    class FileSystem:
        def __init__(self):
            self.root = FileSystemNode()

        def _traverse(self, path, create=True):
            node = self.root
            for part in path.split('/'):
                if not part:
                    continue
                if part not in node.children:
                    if not create:
                        return None
                    node.children[part] = FileSystemNode()
                node = node.children[part]
            return node

        def ls(self, path):
            node = self._traverse(path)
            if node.content:
                return [path.split('/')[-1]]
            return sorted(node.children.keys())

        def mkdir(self, path):
            self._traverse(path)

        def addContentToFile(self, filePath, content):
            node = self._traverse(filePath)
            node.content += content

        def readContentFromFile(self, filePath):
            return self._traverse(filePath).content

    fs = FileSystem()
    results = []
    for op, args in zip(operations, args_list):
        if op == 'ls':
            results.append(fs.ls(args[0]))
        elif op == 'mkdir':
            fs.mkdir(args[0])
            results.append(None)
        elif op == 'addContentToFile':
            fs.addContentToFile(args[0], args[1])
            results.append(None)
        elif op == 'readContentFromFile':
            results.append(fs.readContentFromFile(args[0]))
    return results

