function solution(operations, argsList) {
  class FileSystemNode {
    constructor() { this.children = {}; this.content = ''; }
  }
  class FileSystem {
    constructor() { this.root = new FileSystemNode(); }
    _traverse(path, create=true) {
      let node = this.root;
      for (const part of path.split('/')) {
        if (!part) continue;
        if (!(part in node.children)) {
          if (!create) return null;
          node.children[part] = new FileSystemNode();
        }
        node = node.children[part];
      }
      return node;
    }
    ls(path) {
      const node = this._traverse(path);
      if (node.content) return [path.split('/').filter(p=>p).pop() || ''];
      return Object.keys(node.children).sort();
    }
    mkdir(path) { this._traverse(path); }
    addContentToFile(fp, content) { this._traverse(fp).content += content; }
    readContentFromFile(fp) { return this._traverse(fp).content; }
  }
  const fs = new FileSystem();
  return operations.map((op, i) => {
    const args = argsList[i];
    if (op === 'ls') return fs.ls(args[0]);
    if (op === 'mkdir') { fs.mkdir(args[0]); return null; }
    if (op === 'addContentToFile') { fs.addContentToFile(args[0], args[1]); return null; }
    if (op === 'readContentFromFile') return fs.readContentFromFile(args[0]);
    return null;
  });
}

