def solution(operations, values):
    size = 1000
    buckets = [[] for _ in range(size)]

    def _hash(key):
        return key % size

    def put(key, value):
        h = _hash(key)
        for i, (k, v) in enumerate(buckets[h]):
            if k == key:
                buckets[h][i] = (key, value)
                return
        buckets[h].append((key, value))

    def get(key):
        h = _hash(key)
        for k, v in buckets[h]:
            if k == key:
                return v
        return -1

    def remove(key):
        h = _hash(key)
        buckets[h] = [(k, v) for k, v in buckets[h] if k != key]

    results = []
    for op, val in zip(operations, values):
        if op == "put":
            put(val[0], val[1])
            results.append(None)
        elif op == "get":
            results.append(get(val[0]))
        elif op == "remove":
            remove(val[0])
            results.append(None)
    return results

