function solution(operations, values) {
  const size = 1000;
  const buckets = Array.from({length: size}, () => []);

  function _hash(key) {
    return key % size;
  }

  function put(key, value) {
    const h = _hash(key);
    for (let i = 0; i < buckets[h].length; i++) {
      if (buckets[h][i][0] === key) {
        buckets[h][i] = [key, value];
        return;
      }
    }
    buckets[h].push([key, value]);
  }

  function get(key) {
    const h = _hash(key);
    for (const [k, v] of buckets[h]) {
      if (k === key) return v;
    }
    return -1;
  }

  function remove(key) {
    const h = _hash(key);
    buckets[h] = buckets[h].filter(([k, v]) => k !== key);
  }

  const results = [];
  for (let i = 0; i < operations.length; i++) {
    const op = operations[i];
    const val = values[i];
    if (op === 'put') {
      put(val[0], val[1]);
      results.push(null);
    } else if (op === 'get') {
      results.push(get(val[0]));
    } else if (op === 'remove') {
      remove(val[0]);
      results.push(null);
    }
  }
  return results;
}

