def solution(numerator: int, denominator: int) -> str:
    if numerator == 0:
        return "0"
    sign = "-" if (numerator < 0) ^ (denominator < 0) else ""
    numerator, denominator = abs(numerator), abs(denominator)
    integer_part = numerator // denominator
    remainder = numerator % denominator
    if remainder == 0:
        return sign + str(integer_part)
    decimal_part = []
    remainder_map = {}
    while remainder != 0:
        if remainder in remainder_map:
            idx = remainder_map[remainder]
            decimal_part.insert(idx, "(")
            decimal_part.append(")")
            break
        remainder_map[remainder] = len(decimal_part)
        remainder *= 10
        decimal_part.append(str(remainder // denominator))
        remainder %= denominator
    return sign + str(integer_part) + "." + "".join(decimal_part)

