function solution(numerator, denominator) {
  if (numerator === 0) return "0";
  const sign = ((numerator < 0) ^ (denominator < 0)) ? "-" : "";
  numerator = Math.abs(numerator);
  denominator = Math.abs(denominator);
  const integerPart = Math.floor(numerator / denominator);
  let remainder = numerator % denominator;
  if (remainder === 0) return sign + integerPart.toString();
  const decimalPart = [];
  const remainderMap = new Map();
  while (remainder !== 0) {
    if (remainderMap.has(remainder)) {
      const idx = remainderMap.get(remainder);
      decimalPart.splice(idx, 0, "(");
      decimalPart.push(")");
      break;
    }
    remainderMap.set(remainder, decimalPart.length);
    remainder *= 10;
    decimalPart.push(Math.floor(remainder / denominator).toString());
    remainder %= denominator;
  }
  return sign + integerPart.toString() + "." + decimalPart.join("");
}

