  let candidate1 = null, candidate2 = null;
  let count1 = 0, count2 = 0;

  for (const num of nums) {
    if (num === candidate1) {
      count1++;
    } else if (num === candidate2) {
      count2++;
    } else if (count1 === 0) {
      candidate1 = num;
      count1 = 1;
    } else if (count2 === 0) {
      candidate2 = num;
      count2 = 1;
    } else {
      count1--;
      count2--;
    }
  }

  const threshold = Math.floor(nums.length / 3);
  const result = [];
  if (candidate1 !== null && nums.filter(x => x === candidate1).length > threshold) {
    result.push(candidate1);
  }
