function solution(operations) {
  const store = new Map(); // key -> {value, expireAt}
  let currentTime = 0.0;
  const results = [];

  for (const op of operations) {
    if (op[0] === 'set') {
      const [, key, value, ttl] = op;
      const expireAt = currentTime + ttl;
      store.set(key, { value, expireAt });
      results.push(null);
    } else if (op[0] === 'get') {
      const [, key] = op;
      if (!store.has(key)) {
        results.push(null);
      } else {
        const { value, expireAt } = store.get(key);
        if (currentTime > expireAt) {
          store.delete(key);
          results.push(null);
        } else {
          results.push(value);
        }
      }
    } else if (op[0] === 'delete') {
      const [, key] = op;
      if (store.has(key)) {
        store.delete(key);
        results.push(true);
      } else {
        results.push(false);
      }
    } else if (op[0] === 'advance') {
      const [, seconds] = op;
      currentTime += seconds;
      results.push(null);
    } else if (op[0] === 'cleanup') {
      const expired = [];
      for (const [k, { expireAt }] of store.entries()) {
        if (currentTime > expireAt) expired.push(k);
      }
      for (const k of expired) store.delete(k);
      results.push(expired.length);
    } else {
      results.push(null);
    }
  }

  return results;
}

