    motorcycle: Array.from({length: num_motorcycle}, (_, i) => i).sort((a,b) => a-b),
    car: Array.from({length: num_car}, (_, i) => i).sort((a,b) => a-b),
    bus: Array.from({length: num_bus}, (_, i) => i).sort((a,b) => a-b)
  };
  const spotToType = {};
  for (const [t, spots] of Object.entries(available)) {
    for (const s of spots) spotToType[`${t}${s}`] = t;
  }
  const results = [];
  for (let i = 0; i < commands.length; i++) {
    const cmd = commands[i], arg = cmdArgs[i];
    if (cmd === 'park') {
      if (!available[arg] || available[arg].length === 0) {
        results.push('-1');
      } else {
        const spotNum = available[arg].shift();
        results.push(`${arg}${spotNum}`);
      }
    } else if (cmd === 'leave') {
      if (!(arg in spotToType)) {
        results.push(false);
      } else {
        const vtype = spotToType[arg];
        const spotNum = parseInt(arg.slice(vtype.length));
        let lo = 0, hi = available[vtype].length;
        while (lo < hi) { const mid = (lo+hi)>>1; if (available[vtype][mid] < spotNum) lo=mid+1; else hi=mid; }
        available[vtype].splice(lo, 0, spotNum);
        results.push(true);
      }
    } else if (cmd === 'getAvailableSpots') {
      results.push((available[arg] || []).length);
    }
  }
  return results;
}

