import heapq

def solution(operations, total_time):
    heap = []  # (run_at, seq, name, interval_or_None)
    cancelled = set()
    seq = 0

    for op in operations:
        op_type = op[0]
        name = op[1]
        delay_or_interval = op[2] if len(op) > 2 else None

        if op_type == 'schedule':
            run_at = delay_or_interval
            heapq.heappush(heap, (run_at, seq, name, None))
            seq += 1
        elif op_type == 'schedule_recurring':
            run_at = delay_or_interval
            heapq.heappush(heap, (run_at, seq, name, delay_or_interval))
            seq += 1
        elif op_type == 'cancel':
            cancelled.add(name)

    executed = []

    while heap:
        run_at, s, name, interval = heapq.heappop(heap)
        if run_at > total_time:
            break
        if name in cancelled:
            continue
        executed.append(name)
        if interval is not None:
            next_run = run_at + interval
            if next_run <= total_time:
                heapq.heappush(heap, (next_run, seq, name, interval))
                seq += 1

    return executed

