function solution(operations, total_time) {
  const heap = [];
  const cancelled = new Set();
  let seq = 0;

  function heapPush(item) {
    heap.push(item);
    let i = heap.length - 1;
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (heap[parent][0] < heap[i][0] || (heap[parent][0] === heap[i][0] && heap[parent][1] <= heap[i][1])) break;
      [heap[parent], heap[i]] = [heap[i], heap[parent]];
      i = parent;
    }
  }

  function heapPop() {
    const top = heap[0];
    const last = heap.pop();
    if (heap.length > 0) {
      heap[0] = last;
      let i = 0;
      while (true) {
        let smallest = i;
        const l = 2*i+1, r = 2*i+2;
        if (l < heap.length && (heap[l][0] < heap[smallest][0] || (heap[l][0] === heap[smallest][0] && heap[l][1] < heap[smallest][1]))) smallest = l;
        if (r < heap.length && (heap[r][0] < heap[smallest][0] || (heap[r][0] === heap[smallest][0] && heap[r][1] < heap[smallest][1]))) smallest = r;
        if (smallest === i) break;
        [heap[smallest], heap[i]] = [heap[i], heap[smallest]];
        i = smallest;
      }
    }
    return top;
  }

  for (const op of operations) {
    const op_type = op[0];
    const name = op[1];
    const delay_or_interval = op.length > 2 ? op[2] : null;

    if (op_type === 'schedule') {
      heapPush([delay_or_interval, seq, name, null]);
      seq++;
    } else if (op_type === 'schedule_recurring') {
      heapPush([delay_or_interval, seq, name, delay_or_interval]);
      seq++;
    } else if (op_type === 'cancel') {
      cancelled.add(name);
    }
  }

  const executed = [];

  while (heap.length > 0) {
    const [run_at, s, name, interval] = heapPop();
    if (run_at > total_time) break;
    if (cancelled.has(name)) continue;
    executed.push(name);
    if (interval !== null) {
      const next_run = run_at + interval;
      if (next_run <= total_time) {
        heapPush([next_run, seq, name, interval]);
        seq++;
      }
    }
  }

  return executed;
}

