def solution(graph):
    n = len(graph)
    # 0 = unvisited, 1 = visiting (in cycle path), 2 = safe
    state = [0] * n

    def dfs(node):
        if state[node] == 1:
            return False  # cycle detected
        if state[node] == 2:
            return True   # already confirmed safe

        state[node] = 1  # mark as visiting
        for neighbor in graph[node]:
            if not dfs(neighbor):
                return False  # unsafe path found

        state[node] = 2  # mark as safe
        return True

    return [i for i in range(n) if dfs(i)]

