function solution(k, w, profits, capital) {
  const projects = capital.map((c, i) => [c, profits[i]]);
  projects.sort((a, b) => a[0] - b[0]);

  // Max-heap using a simple priority queue
  const maxHeap = [];

  function heapPush(val) {
    maxHeap.push(val);
    let i = maxHeap.length - 1;
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (maxHeap[parent] < maxHeap[i]) {
        [maxHeap[parent], maxHeap[i]] = [maxHeap[i], maxHeap[parent]];
        i = parent;
      } else break;
    }
  }

  function heapPop() {
    const top = maxHeap[0];
    const last = maxHeap.pop();
    if (maxHeap.length > 0) {
      maxHeap[0] = last;
      let i = 0;
      while (true) {
        let largest = i;
        const l = 2 * i + 1, r = 2 * i + 2;
        if (l < maxHeap.length && maxHeap[l] > maxHeap[largest]) largest = l;
        if (r < maxHeap.length && maxHeap[r] > maxHeap[largest]) largest = r;
        if (largest !== i) {
          [maxHeap[largest], maxHeap[i]] = [maxHeap[i], maxHeap[largest]];
          i = largest;
        } else break;
      }
    }
    return top;
  }

  let idx = 0;
  const n = projects.length;

  for (let round = 0; round < k; round++) {
    while (idx < n && projects[idx][0] <= w) {
      heapPush(projects[idx][1]);
      idx++;
    }
    if (maxHeap.length === 0) break;
    w += heapPop();
  }

  return w;
}

