    visited = {s}
    queue = deque([s])
    found = False

    while queue:
        level_size = len(queue)
        for _ in range(level_size):
            curr = queue.popleft()
            if is_valid(curr):
                result.append(curr)
                found = True
            if found:
                continue
            for i in range(len(curr)):
                if curr[i] not in '()':
                    continue
                candidate = curr[:i] + curr[i+1:]
                if candidate not in visited:
                    visited.add(candidate)
                    queue.append(candidate)
