function solution(buildings) {
  const events = [];
  for (const [l, r, h] of buildings) {
    events.push([l, -h, r]);
    events.push([r, 0, 0]);
  }
  events.sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]);

  // MinHeap simulation using sorted structure
  // We'll use a max-heap via negation with lazy deletion
  class MaxHeap {
    constructor() { this.data = [[0, Infinity]]; }
    push(val) {
      this.data.push(val);
      this._bubbleUp(this.data.length - 1);
    }
    pop() {
      const top = this.data[0];
      const last = this.data.pop();
      if (this.data.length > 0) {
        this.data[0] = last;
        this._sinkDown(0);
      }
      return top;
    }
    peek() { return this.data[0]; }
    size() { return this.data.length; }
    _bubbleUp(i) {
      while (i > 0) {
        const parent = Math.floor((i - 1) / 2);
        if (this.data[parent][0] < this.data[i][0] || 
            (this.data[parent][0] === this.data[i][0] && this.data[parent][1] > this.data[i][1])) {
          [this.data[parent], this.data[i]] = [this.data[i], this.data[parent]];
          i = parent;
        } else break;
      }
    }
    _sinkDown(i) {
      const n = this.data.length;
      while (true) {
        let largest = i;
        const l = 2*i+1, r = 2*i+2;
        if (l < n && this.data[l][0] > this.data[largest][0]) largest = l;
        if (r < n && this.data[r][0] > this.data[largest][0]) largest = r;
        if (largest !== i) {
          [this.data[largest], this.data[i]] = [this.data[i], this.data[largest]];
          i = largest;
        } else break;
      }
    }
  }

  const heap = new MaxHeap();
  const result = [];
  let prevMax = 0;

  for (const [x, negH, end] of events) {
    if (negH !== 0) {
      heap.push([-negH, end]);
    }
    while (heap.peek()[1] <= x) {
      heap.pop();
    }
    const curMax = heap.peek()[0];
    if (curMax !== prevMax) {
      result.push([x, curMax]);
      prevMax = curMax;
    }
  }

  return result;
}

