function solution(commands, args) {
  let timestamp = 0;
  const tweets = new Map();
  const following = new Map();

  function getTweets(uid) {
    if (!tweets.has(uid)) tweets.set(uid, []);
    return tweets.get(uid);
  }
  function getFollowing(uid) {
    if (!following.has(uid)) following.set(uid, new Set());
    return following.get(uid);
  }

  function postTweet(userId, tweetId) {
    getTweets(userId).push([timestamp++, tweetId]);
  }

  function getNewsFeed(userId) {
    const sources = new Set([...getFollowing(userId), userId]);
    // min-heap via sorted array approach for simplicity
    let candidates = [];
    for (const uid of sources) {
      const ut = getTweets(uid);
      if (ut.length > 0) {
        candidates.push([uid, ut.length - 1]);
      }
    }
    const result = [];
    while (candidates.length > 0 && result.length < 10) {
      let bestI = 0;
      for (let i = 1; i < candidates.length; i++) {
        const [ua, ia] = candidates[bestI];
        const [ub, ib] = candidates[i];
        if (tweets.get(ub)[ib][0] > tweets.get(ua)[ia][0]) bestI = i;
      }
      const [uid, idx] = candidates[bestI];
      result.push(tweets.get(uid)[idx][1]);
      if (idx > 0) candidates[bestI] = [uid, idx - 1];
      else candidates.splice(bestI, 1);
    }
    return result;
  }

  const results = [];
  for (let i = 0; i < commands.length; i++) {
    const cmd = commands[i], arg = args[i];
    if (cmd === 'Twitter') results.push(null);
    else if (cmd === 'postTweet') { postTweet(arg[0], arg[1]); results.push(null); }
    else if (cmd === 'getNewsFeed') results.push(getNewsFeed(arg[0]));
    else if (cmd === 'follow') { getFollowing(arg[0]).add(arg[1]); results.push(null); }
    else if (cmd === 'unfollow') { getFollowing(arg[0]).delete(arg[1]); results.push(null); }
  }
  return results;
}

