function solution(k, operations, arguments_) {
  let size = k;
  let queue = new Array(k).fill(0);
  let head = 0, tail = 0, count = 0;

  function enqueue(value) {
    if (count === size) return false;
    queue[tail] = value;
    tail = (tail + 1) % size;
    count++;
    return true;
  }

  function dequeue() {
    if (count === 0) return false;
    head = (head + 1) % size;
    count--;
    return true;
  }

  function Front() {
    return count === 0 ? -1 : queue[head];
  }

  function Rear() {
    return count === 0 ? -1 : queue[((tail - 1) % size + size) % size];
  }

  function isEmpty() {
    return count === 0;
  }

  function isFull() {
    return count === size;
  }

  const results = [];
  for (let i = 0; i < operations.length; i++) {
    const op = operations[i];
    const arg = arguments_[i];
    if (op === 'enqueue') results.push(enqueue(arg[0]));
    else if (op === 'dequeue') results.push(dequeue());
    else if (op === 'Front') results.push(Front());
    else if (op === 'Rear') results.push(Rear());
    else if (op === 'isEmpty') results.push(isEmpty());
    else if (op === 'isFull') results.push(isFull());
  }
  return results;
}

