function solution(operations, values) {
  // Min-heap and max-heap implementations
  class MaxHeap {
    constructor() { this.data = []; }
    push(val) {
      this.data.push(val);
      this._bubbleUp(this.data.length - 1);
    }
    pop() {
      const top = this.data[0];
      const last = this.data.pop();
      if (this.data.length > 0) {
        this.data[0] = last;
        this._sinkDown(0);
      }
      return top;
    }
    peek() { return this.data[0]; }
    size() { return this.data.length; }
    _bubbleUp(i) {
      while (i > 0) {
        const parent = Math.floor((i - 1) / 2);
        if (this.data[parent] < this.data[i]) {
          [this.data[parent], this.data[i]] = [this.data[i], this.data[parent]];
          i = parent;
        } else break;
      }
    }
    _sinkDown(i) {
      const n = this.data.length;
      while (true) {
        let largest = i;
        const l = 2*i+1, r = 2*i+2;
        if (l < n && this.data[l] > this.data[largest]) largest = l;
        if (r < n && this.data[r] > this.data[largest]) largest = r;
        if (largest !== i) {
          [this.data[largest], this.data[i]] = [this.data[i], this.data[largest]];
          i = largest;
        } else break;
      }
    }
  }
  class MinHeap {
    constructor() { this.data = []; }
    push(val) {
      this.data.push(val);
      this._bubbleUp(this.data.length - 1);
    }
    pop() {
      const top = this.data[0];
      const last = this.data.pop();
      if (this.data.length > 0) {
        this.data[0] = last;
        this._sinkDown(0);
      }
      return top;
    }
    peek() { return this.data[0]; }
    size() { return this.data.length; }
    _bubbleUp(i) {
      while (i > 0) {
        const parent = Math.floor((i - 1) / 2);
        if (this.data[parent] > this.data[i]) {
          [this.data[parent], this.data[i]] = [this.data[i], this.data[parent]];
          i = parent;
        } else break;
      }
    }
    _sinkDown(i) {
      const n = this.data.length;
      while (true) {
        let smallest = i;
        const l = 2*i+1, r = 2*i+2;
        if (l < n && this.data[l] < this.data[smallest]) smallest = l;
        if (r < n && this.data[r] < this.data[smallest]) smallest = r;
        if (smallest !== i) {
          [this.data[smallest], this.data[i]] = [this.data[i], this.data[smallest]];
          i = smallest;
        } else break;
      }
    }
  }

  const maxHeap = new MaxHeap(); // lower half
  const minHeap = new MinHeap(); // upper half
  const results = [];

  for (let i = 0; i < operations.length; i++) {
    const op = operations[i];
    const val = values[i];
    if (op === 'addNum') {
      maxHeap.push(val);
      if (minHeap.size() > 0 && maxHeap.peek() > minHeap.peek()) {
        minHeap.push(maxHeap.pop());
      }
      if (maxHeap.size() > minHeap.size() + 1) {
        minHeap.push(maxHeap.pop());
      } else if (minHeap.size() > maxHeap.size()) {
        maxHeap.push(minHeap.pop());
      }
    } else if (op === 'findMedian') {
      if (maxHeap.size() > minHeap.size()) {
        results.push(maxHeap.peek());
      } else {
        results.push((maxHeap.peek() + minHeap.peek()) / 2.0);
      }
    }
  }
  return results;
}

