      parent[x] = parent[parent[x]];
      x = parent[x];
    }
    return x;
  }
  function union(x, y) {
    const px = find(x), py = find(y);
    if (px === py) return false;
    parent[px] = py;
    return true;
  }
  for (const [u, v] of edges) {
    if (!union(u, v)) return [u, v];
  }
