from collections import defaultdict, OrderedDict

def solution(operations, args):
    cache = None
    results = []

    class LFUCache:
        def __init__(self, capacity):
            self.capacity = capacity
            self.min_freq = 0
            self.key_map = {}  # key -> [value, freq]
            self.freq_map = defaultdict(OrderedDict)  # freq -> OrderedDict{key: None}

        def _update(self, key):
            val, freq = self.key_map[key]
            del self.freq_map[freq][key]
            if not self.freq_map[freq] and self.min_freq == freq:
                self.min_freq += 1
            self.key_map[key] = [val, freq + 1]
            self.freq_map[freq + 1][key] = None

        def get(self, key):
            if key not in self.key_map:
                return -1
            self._update(key)
            return self.key_map[key][0]

        def put(self, key, value):
            if self.capacity <= 0:
                return
            if key in self.key_map:
                self.key_map[key][0] = value
                self._update(key)
            else:
                if len(self.key_map) >= self.capacity:
                    evict_key, _ = self.freq_map[self.min_freq].popitem(last=False)
                    if not self.freq_map[self.min_freq]:
                        del self.freq_map[self.min_freq]
                    del self.key_map[evict_key]
                self.key_map[key] = [value, 1]
                self.freq_map[1][key] = None
                self.min_freq = 1

    for op, arg in zip(operations, args):
        if op == 'LFUCache':
            cache = LFUCache(arg[0])
            results.append(None)
        elif op == 'put':
            cache.put(arg[0], arg[1])
            results.append(None)
        elif op == 'get':
            results.append(cache.get(arg[0]))

    return results

