function solution(operations, args) {
  class LFUCache {
    constructor(capacity) {
      this.capacity = capacity;
      this.minFreq = 0;
      this.keyMap = new Map(); // key -> {value, freq}
      this.freqMap = new Map(); // freq -> Map(key -> null) (insertion-order = LRU)
    }

    _update(key) {
      const { value, freq } = this.keyMap.get(key);
      this.freqMap.get(freq).delete(key);
      if (this.freqMap.get(freq).size === 0) {
        this.freqMap.delete(freq);
        if (this.minFreq === freq) this.minFreq++;
      }
      this.keyMap.set(key, { value, freq: freq + 1 });
      if (!this.freqMap.has(freq + 1)) this.freqMap.set(freq + 1, new Map());
      this.freqMap.get(freq + 1).set(key, null);
    }

    get(key) {
      if (!this.keyMap.has(key)) return -1;
      this._update(key);
      return this.keyMap.get(key).value;
    }

    put(key, value) {
      if (this.capacity <= 0) return;
      if (this.keyMap.has(key)) {
        this.keyMap.get(key).value = value;
        this._update(key);
      } else {
        if (this.keyMap.size >= this.capacity) {
          const evictMap = this.freqMap.get(this.minFreq);
          const evictKey = evictMap.keys().next().value;
          evictMap.delete(evictKey);
          if (evictMap.size === 0) this.freqMap.delete(this.minFreq);
          this.keyMap.delete(evictKey);
        }
        this.keyMap.set(key, { value, freq: 1 });
        if (!this.freqMap.has(1)) this.freqMap.set(1, new Map());
        this.freqMap.get(1).set(key, null);
        this.minFreq = 1;
      }
    }
  }

  let cache = null;
  const results = [];
  for (let i = 0; i < operations.length; i++) {
    const op = operations[i], arg = args[i];
    if (op === 'LFUCache') {
      cache = new LFUCache(arg[0]);
      results.push(null);
    } else if (op === 'put') {
      cache.put(arg[0], arg[1]);
      results.push(null);
    } else if (op === 'get') {
      results.push(cache.get(arg[0]));
    }
  }
  return results;
}

