  const stack = []; // [start, height]
  let maxArea = 0;
  for (let i = 0; i < h.length; i++) {
    let start = i;
    while (stack.length > 0 && stack[stack.length - 1][1] >= h[i]) {
      const [idx, height] = stack.pop();
