function solution(root) {
  // Serialize
  const tokens = [];
  function dfs(node) {
    if (!node) {
      tokens.push('null');
      return;
    }
    tokens.push(String(node.val));
    dfs(node.left);
    dfs(node.right);
  }
  dfs(root);
  const data = tokens.join(',');

  // Deserialize
  const parts = data.split(',');
  let idx = 0;
  function build() {
    const val = parts[idx++];
    if (val === 'null') return null;
    const node = { val: parseInt(val), left: null, right: null };
    node.left = build();
    node.right = build();
    return node;
  }
  return build();
}

